import{_ as t,o as e,c as a,Q as i}from"./chunks/framework.2275ac6f.js";const p=JSON.parse('{"title":"数字签名与消息认证","description":"","frontmatter":{"title":"数字签名与消息认证","date":"2021-05-07T10:42:55.000Z","tags":["信息安全"],"published":true,"hideInList":false,"feature":null,"isTop":false},"headers":[{"level":2,"title":"定义","slug":"定义","link":"#定义","children":[]},{"level":2,"title":"Attacks on digital signature","slug":"attacks-on-digital-signature","link":"#attacks-on-digital-signature","children":[]},{"level":2,"title":"流程","slug":"流程","link":"#流程","children":[]},{"level":2,"title":"算法","slug":"算法","link":"#算法","children":[]}],"relativePath":"src/信息安全/数字签名与消息认证.md","lastUpdated":1718000534000}'),l={name:"src/信息安全/数字签名与消息认证.md"},s=i('<p>数字签名写借条，就算借条丢了也能还原（王继林教授说支付宝就用的这个数字签名）</p><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-hidden="true">#</a></h2><p>以电子形式模拟搜狐写签名（hand-written signature）</p><ul><li>Unforgeability 不可伪造</li><li>Undeniability 不可抵赖</li></ul><p><strong>Requirements:</strong></p><ul><li>依赖于被签署的文件</li><li>快速计算（compute）</li><li>任何人都能验证</li><li>易于存储 should be short enough</li></ul><h2 id="attacks-on-digital-signature" tabindex="-1">Attacks on digital signature <a class="header-anchor" href="#attacks-on-digital-signature" aria-hidden="true">#</a></h2><p><strong>Attack type：</strong></p><ul><li>key-only attack 只知道公钥，想办法伪造（攻击难度大，所以比较容易防治）</li><li>Known-message attack 已知一部分消息及其签名，对新消息使用就签名想办法伪造</li><li>Chosen-message attack 对相似消息的签名进行分析，想办法签名新的消息</li></ul><p>对于上面这个无序列表，某个方案能抗击下面的攻击，则必然能抗击上面的攻击。</p><h2 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-hidden="true">#</a></h2><p>signer使用私钥对msg签名，验证者使用signer的公钥对签名进行验证</p><p><strong>Usage：</strong> off-line：签名 on-line：验证</p><p>a想要验证b是不是b，则对b发送m，b使用b的私钥对m进行签名，a使用b的公钥对m的签名进行验证，如果b是真的b，则验证通过，反之通不过 <strong>Digital Signature Law is Infrastructure</strong></p><h2 id="算法" tabindex="-1">算法 <a class="header-anchor" href="#算法" aria-hidden="true">#</a></h2><ul><li>基于纠错码</li><li>基于椭圆切线</li><li>基于 two hard problem 典型的： <ol><li>RSA（基于大数分解） 消息可能很大，所以需要先hash下，变成256位，再签名 现在一般是使用sha-256进行hash</li><li>ElGamal（离散对数）</li></ol></li></ul><p><strong>E-cash：</strong> 电子签名，基于盲签名</p>',17),n=[s];function r(o,d,h,c,g,u){return e(),a("div",null,n)}const f=t(l,[["render",r]]);export{p as __pageData,f as default};
